#include <stdio.h>

int main() {
    int target = 67; // Sabit hedef sayi (demo amacli)

    printf("Sayi tahmin oyunu basladi! (1-100 arasi)\n");
    printf("(Bu demo, onceden belirlenmis tahminlerle calisir)\n\n");

    int guesses[] = {50, 75, 62, 68, 65, 67};
    int guessCount = 6;
    int found = 0;

    for (int i = 0; i < guessCount; i++) {
        int guess = guesses[i];
        printf("Tahmin: %d\n", guess);

        if (guess == target) {
            printf("Tebrikler! Dogru tahmin: %d\n", target);
            found = 1;
            break;
        } else if (guess < target) {
            printf("Daha buyuk bir sayi dene.\n\n");
        } else {
            printf("Daha kucuk bir sayi dene.\n\n");
        }
    }

    if (!found) {
        printf("\nTahmin edilemedi. Dogru sayi: %d\n", target);
    }

    printf("\nToplam deneme sayisi: %d\n", guessCount);

    return 0;
}
